cssVars:
:root {
  --color-primary: #6366F1;
  --color-primary-hover: #4F46E5;
  --color-secondary: #EC4899;
  --color-surface: rgba(255, 255, 255, 0.1);
  --color-background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
  --color-card: rgba(255, 255, 255, 0.15);
  --color-text: #FFFFFF;
  --color-text-muted: rgba(255, 255, 255, 0.7);
  --color-border: rgba(255, 255, 255, 0.2);
  --color-error: #F87171;
  --color-success: #34D399;
  --color-warning: #FBBF24;
  --color-info: #38BDF8;
  --font-heading: Inter, system-ui, sans-serif;
  --font-body: Inter, system-ui, sans-serif;
  --font-mono: JetBrains Mono, monospace;
  --radius-sm: 8px;
  --radius-md: 12px;
  --radius-lg: 16px;
  --radius-xl: 24px;
  --radius-full: 9999px;
  --shadow-sm: 0 2px 8px rgba(31,38,135,0.2);
  --shadow-md: 0 8px 32px rgba(31,38,135,0.3);
  --shadow-lg: 0 16px 48px rgba(31,38,135,0.4);
  --shadow-xl: 0 32px 64px rgba(31,38,135,0.5);
  --special-backdrop-filter: blur(16px) saturate(180%);
  --special--webkit-backdrop-filter: blur(16px) saturate(180%);
}
